#!/usr/bin/env python3
import base64, os, sys
if not os.path.isdir("screens"): sys.exit("Run from BatKnock root")

os.makedirs("screens", exist_ok=True)
with open("screens/CreateBatScreen.js", "wb") as f:
    f.write(base64.b64decode(""))
print("OK screens/CreateBatScreen.js")

with open("App.js", "wb") as f:
    f.write(base64.b64decode(""))
print("OK App.js")

